import prometheus_client as prom
from prometheus_client.core import GaugeMetricFamily
import time

# Define the Prometheus metrics
username_metric = GaugeMetricFamily('database_username', 'Database username', labels=['host'])
password_metric = GaugeMetricFamily('database_password', 'Database password', labels=['host'])
host_metric = GaugeMetricFamily('database_host', 'Database host', labels=['host'])
connection_string_metric = GaugeMetricFamily('database_connection_string', 'Database connection string', labels=['host'])

# Example database credentials
credentials = {
    'host1': {'username': 'user1', 'password': 'pass1', 'connection_string': 'conn_str1'},
    'host2': {'username': 'user2', 'password': 'pass2', 'connection_string': 'conn_str2'}
}

def collect_metrics():
    for host, details in credentials.items():
        username_metric.add_metric([host], details['username'])
        password_metric.add_metric([host], details['password'])
        host_metric.add_metric([host], details['host'])
        connection_string_metric.add_metric([host], details['connection_string'])

# Start the Prometheus HTTP server
prom.start_http_server(8000)

while True:
    collect_metrics()
    prom.push_to_gateway('localhost:9091', job='database_credentials')
    time.sleep(60)